
function setup() {
    createCanvas(600, 400);
    background('#fff');
    noStroke()
}

function draw() {
    fill('#2e354f')
    rect(0, 350, 600, 100)
    fill('#5c6b99')
    rect(0, 250, 600, 100)
    fill('#9da6c3')
    rect(0, 150, 600, 100)
    fill('#dee0ec')
    rect(0, 50, 600, 100)
    fill('#ffffff')
    rect(0, -50, 600, 100)
    fill('#2e354f')
  
    arc(0*150+75, 350, 150, 35, PI*1, PI*2)
    arc(2*150+75, 350, 150, 35, PI*1, PI*2)
    arc(4*150+75, 350, 150, 35, PI*1, PI*2)
    fill('#5c6b99')
    arc(1*150+75, 350, 150, 35, PI*0, PI*1)
    arc(3*150+75, 350, 150, 35, PI*0, PI*1)
  
    arc(1*150+5, 250, 150, 35, PI*1, PI*2)
    arc(3*150+5, 250, 150, 35, PI*1, PI*2)
    fill('#9da6c3')
    arc(0*150+5, 250, 150, 35, PI*0, PI*1)
    arc(2*150+5, 250, 150, 35, PI*0, PI*1)
    arc(4*150+5, 250, 150, 35, PI*0, PI*1)
  
    arc(0*150+50, 150, 150, 35, PI*1, PI*2)
    arc(2*150+50, 150, 150, 35, PI*1, PI*2)
    arc(4*150+50, 150, 150, 35, PI*1, PI*2)
    fill('#dee0ec')
    arc(1*150+50, 150, 150, 35, PI*0, PI*1)
    arc(3*150+50, 150, 150, 35, PI*0, PI*1)

    arc(0*150+10, 50, 150, 35, PI*1, PI*2)
    arc(2*150+10, 50, 150, 35, PI*1, PI*2)
    arc(4*150+10, 50, 150, 35, PI*1, PI*2)
    fill('#ffffff')
    arc(1*150+10, 50, 150, 35, PI*0, PI*1)
    arc(3*150+10, 50, 150, 35, PI*0, PI*1)

}

